INSERT INTO `page_sections` VALUES (10,1,'pm_yojna','single',NULL,'About Pradhan Mantri TB Mukat Bharat Abhiyan','The Pradhan Mantri TB Mukat Bharat Abhiyan is a nationwide initiative aimed at eliminating tuberculosis in India by 2025. The program focuses on early detection, uninterrupted treatment, nutritional support, and multi-sectoral coordination.','Tb.jpg',NULL,NULL,4,'2026-02-25 06:30:43','2026-02-25 06:30:43'),(11,1,'ministry','single',NULL,'About Ministry','The Ministry of Ayush was formed with a vision of reviving the profound knowledge of our ancient systems of medicine and ensuring the optimal development and propagation of the Ayush systems of healthcare. Earlier, the Department of Indian System of Medicine and Homoeopathy (ISM&H) formed in 1995, was responsible for the development of these systems. It was then renamed as the Department of Ayurveda, Yoga, and Naturopathy, Unani, Siddha and Homoeopathy (Ayush) in November 2003 with focused attention towards education and research in Ayurveda, Yoga and Naturopathy, Unani, Siddha, and Homoeopathy.','',NULL,NULL,5,'2026-02-25 06:31:12','2026-02-25 05:13:59'),(12,1,'aiia','single',NULL,'All India Institute of Ayurveda','The All India Institute of Ayurveda has been conceived as an Apex Institute for Ayurveda. It aims at bringing a synergy between Traditional Wisdom of Ayurveda and Modern tools and technology. The institute would offer postgraduate and doctoral courses in various disciplines of Ayurveda and will focus on fundamental research of Ayurveda, drug development, standardization, quality control, safety evaluation and scientific validation of Ayurvedic medicine. Institute has a 200 bed referral hospital for facilitating clinical research. The Institute has 25 Specialty Departments and 12 clinics with 8 inter-disciplinary research laboratories wherein several Scholars have access for PG & Ph.D programs every year. The hospital is equipped with state of the art modern diagnostic tools and techniques which is used in teaching, training and research. The patient care is done primarily through Ayurveda of tertiary level. This institute also has an international collaborative centre for global promotion and research in Ayurveda.','page_sections/hPAmbBwP1HCtTGHkpHLMOeFP6RJn4gTHxoORgKTW.webp',NULL,NULL,6,'2026-02-25 06:31:25','2026-02-25 04:58:33'),(13,1,'rntcp','single',NULL,'Revised National Tuberculosis Control Programme (RNTCP)','The RNTCP focuses on Detect, Treat, Prevent, and Build strategies to eliminate tuberculosis and strengthen healthcare infrastructure across the country.',NULL,NULL,NULL,7,'2026-02-25 06:31:35','2026-02-25 06:31:35'),(14,1,'roles','multiple',NULL,'Dr. Divya Kajaria','Associate Professor, Department of Kayachikitsa, AIIA Delhi. Unit Incharge and Principal Investigator of PHI Project.','page_sections/q6WNG69eOqmhd6mkAEIdfpB1a6CX7ACstipnian5.png',NULL,NULL,8,'2026-02-25 06:31:48','2026-02-25 05:24:23'),(15,1,'roles','multiple',NULL,'Dr. Ankit Kajaria','Project Consultant, PHI Project.','page_sections/cuBZNSfqPHyiYBrOXocmgSWkOzilJoPhDmTPJ2KO.png',NULL,NULL,9,'2026-02-25 06:31:48','2026-02-25 05:27:34'),(16,1,'roles','multiple',NULL,'Ms. Tulika Singh','Data Entry Operator (DEO), PHI Project.','page_sections/3AP996AkRJiibxXPQlh9JN5x5OLDrdNabw60Asr1.png',NULL,NULL,10,'2026-02-25 06:31:48','2026-02-25 05:27:46'),(23,1,'pm_quote','single',10,'- Shri Narendra Modi','India is a treasure trove of herbal plants it is, in a way our Green Gold.','page_sections/jUrhtvEKkIFJvuCLRe5uFRIKZvrimOQps2J5j06Q.png',NULL,NULL,0,'2026-02-25 04:08:10','2026-02-25 04:21:11'),(24,1,'ministry_sub','single',11,'Shri Prataprao Jadhav','Hon\'ble Minister of State','page_sections/dJG4jSyzQafxosjRmcgZC6v6UieMmjVBcSbTrdjp.jpg',NULL,NULL,0,'2026-02-25 04:35:04','2026-02-25 04:35:04'),(28,1,'objectives rntcp','single',13,NULL,'To achieve and maintain a cure rate of at least 85% among newly detected infectious (new sputum smear positive) cases',NULL,NULL,NULL,0,'2026-02-25 04:59:54','2026-02-25 04:59:54'),(29,1,'objective rntcp','single',13,NULL,'To achieve and maintain detection of at least 70% of such cases in the population.',NULL,NULL,NULL,0,'2026-02-25 05:00:11','2026-02-25 05:00:33'),(30,1,'description','single',14,NULL,'Unit Incharge, Principal Investigator of PHI Project',NULL,NULL,NULL,0,'2026-02-25 05:27:07','2026-02-25 05:27:07'),(31,1,'roles','single',NULL,'Mr. Deepak','Health Worker, Pharmacy Attendant PHI Project','page_sections/NXAbho5nteFMu8nWSiZWnq0Kh4w5Ut2G3TxNCHkS.png',NULL,NULL,11,'2026-02-25 05:28:52','2026-02-25 05:29:03'),(32,1,'roles','single',NULL,'Mr. Vikas','MTS, Lab Attendant PHI Project','page_sections/yRCdzQvTor3pT3iZXcFs9SpJIvx7T7aq5J28DnJE.png',NULL,NULL,12,'2026-02-25 05:29:24','2026-02-25 05:29:24'),(33,1,'roles','single',NULL,'Mr. Vipin','MTS, Awareness and Screening staff','page_sections/o1gI9uC1AGrTJShRWmVVOJ0mTa8pfHpT6IuviLNo.png',NULL,NULL,13,'2026-02-25 05:29:33','2026-02-25 05:30:05'),(34,2,'project_detail','single',NULL,'Aims Of Projects','Project entitled as \"Promotion of Ayurvedic Medicines and Rasayan Therapy for the management of Latent Tuberculosis (LTBI) in Indian Population\" is initiated under the Scheme of Grant-in-aid for Promotion of Ayush intervention in Public Health Initiatives (PHI).','page_sections/mwswAFWu0tgOhmNwYvHX1X1S48yqJjBRXetSoyPm.jpg',NULL,NULL,0,'2026-02-25 07:45:54','2026-04-11 09:39:39'),(35,2,'scheme','single',NULL,'Central Sector Scheme For Ayurswasthya Yojana & Public Health Intervention (PHI) Scheme','India is a country with heterogeneous health status, which varies in state to state. With almost one-fifth of the world’s population India is going through an epidemiological transition. India is facing triple burden of diseases comprising Non-communicable diseases, communicable diseases and reproductive child health issues. The comprehensive India’s health and socio-economic health indicators are not touching the optimum level irrespective of different measures are implemented. Hence, there is a gap in public health care services. Several organizations have documented that, India needs large amount of health care structures, health care staff / workers and medicines to improve the health care scenario. Number of diseases like diabetes, Arthritis, Cancer, vector borne diseases, viral diseases emerged from time to time. Moreover, in the year 2020, COVID- 19 pandemic pointed out the actual healthcare scenario of India where, the importance and necessity of AYUSH system of medicines and AYUSH manpower are observed.\r\n\r\nThe present Public Health Intervention (PHI) scheme is being implemented since 11th Five Year plan, i.e. from 2007-08 and still continuing successfully. Scheme is basically developed to demonstrate efficacy of AYUSH systems on different Public Health programmes and public health issues through AYUSH intervention. So that, intervention can be taken up in large scale for implementation in National Health Programmes . Since beginning Ministry has sanctioned total 67 projects in different state under this scheme for AYUSH intervention in different public health issues like Type – II Diabetes, Hypertension, various communicable diseases, vector borne diseases, Ante natal care, Musculoskeletal disorders, Anaemia, De-addiction, etc. These were taken up in National AYUSH Mission for its wider application. Moreover, this scheme is going to be implemented as per the discussion in Group of Secretaries meeting and resources persons in the Ministry of AYUSH. This scheme is not similar with any other schemes of the Ministry of AYUSH. As for example AYUSH intervention on G6PD deficiency, AYUSH intervention for substance abuse and de-addiction, AYUSH intervention for oral health care, AYUSH intervention for musculoskeletal disorders etc. are being implemented under this scheme. The experience and the generated evidences of the projects may be shared with other Ministries for future Policy development in the field of AYUSH and health care.\r\n\r\nFurther, given the growing consumer acceptance of AYUSH in the domestic and global society as an important component of pluralistic schemes of healthcare, the Govt. of India had decided to identify reputed institutions engaged in AYUSH Education / Drug Development & Research / Clinical Research etc. in Government/ Non-Government Nonprofit and to support them to upgrade their functions and facilities to levels of excellence under the scheme Centre of Excellence. This scheme also stated in 11th Plan period and successfully continuing till date . Till date 34 projects have been sanctioned under this scheme. Out of which 9 pharmacopoeia labs developed, 22 AYUSH research organization upgraded and 2 AYUSH hospitals upgraded with the quality services, 7 AYUSH journals published. Moreover, specific centers are being developed, which are also being utilized for specialized training under CREV programme. Hence young professionals are also getting trained, keeping these points; Ministry conjointly forms a bigger scheme. From above point of view to implement and merge these two schemes in a wider and larger way Ministry is proposing one big scheme in the name of Ayurswasthya Yojana.',NULL,NULL,NULL,0,'2026-02-25 07:47:30','2026-02-25 07:47:30'),(36,2,'scheme_sub','single',35,'Main Component of Ayurswasthya Yojana:','AYUSH and Public Health\r\nAYUSH for Sports medicine\r\nUp-gradation of facilities to Centre of Excellence',NULL,NULL,NULL,0,'2026-02-25 07:48:37','2026-02-25 07:48:37'),(37,2,'scheme_sub','single',35,'Ayush and public health (PHI) Component:','The health interventions areas identified under Sustainable Development Goal-2 (SDG2) and Sustainable Development Goal-3 (SDG3)\r\nAYUSH intervention on common public health issues related with communicable diseases, Non-communicable diseases, MCH, Geriatric care, mental health etc.\r\nAYUSH for Sports medicine.',NULL,NULL,NULL,0,'2026-02-25 07:49:23','2026-02-25 07:49:23'),(38,2,'scheme_sub','single',35,'Objectives of PHI Component:','Roll out of authentic classical AYUSH interventions with Following objectives:\r\nTo promote AYUSH intervention for community health care.\r\nTo demonstrate advantages of AYUSH health care in public health.\r\nTo support for implementing SDG2 and SDG 3 through integrating AYUSH system.\r\nDocumentation of the efficacy of AYUSH systems through AYUSH interventions in various public health issues which can be taken up in larger scale for implementation in national health programmes.',NULL,NULL,NULL,0,'2026-02-25 07:50:08','2026-02-25 07:50:08'),(39,2,'ntpc','single',NULL,'About NTPC OPD Details','Project entitled as \"Promotion of Ayurvedic Medicines and Rasayan Therapy for the management of Latent Tuberculosis (LTBI) in Indian Population\" is initiated under the Scheme of Grant-in-aid for Promotion of Ayush intervention in Public Health Initiatives (PHI).',NULL,NULL,NULL,0,'2026-02-25 07:56:16','2026-04-25 05:58:29'),(40,3,'contact','single',NULL,NULL,NULL,NULL,NULL,NULL,0,'2026-02-25 08:28:39','2026-02-25 08:28:39'),(41,3,'contact_info','single',NULL,'NTPC Campus D-010 All India Institute Of Ayurveda (AIIA)','Mathura Road, Gautam Puri, Sarita Vihar, New Delhi Pin Code: 110076\r\n\r\nMail Id for Reporting format / Query/ Suggestion:\r\nphiltbi533@gmail.com\r\nMobile No.9311391885',NULL,NULL,NULL,0,'2026-02-25 08:29:16','2026-02-25 08:30:18'),(42,3,'contact_map','single',NULL,NULL,'<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3505.8909628637534!2d77.2994399!3d28.5129281!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x390ce6c7c5ddfc47%3A0xe49ac4853033ec42!2sAll%20India%20Institute%20of%20Ayurveda%2C%20Delhi!5e0!3m2!1sen!2sin!4v1771927298774!5m2!1sen!2sin\" width=\"100%\" height=\"235\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>',NULL,NULL,NULL,0,'2026-02-25 08:32:25','2026-02-25 08:32:25'),(43,3,'contact_form','single',NULL,'Feedback Form',NULL,NULL,NULL,NULL,0,'2026-0